+  display: block;
+  margin-top: 2px;
+  color: #111827;
+  font-size: 11px;
+  line-height: 14px;
+  font-weight: 750;
+}
+
+.model-line {
+  display: flex;
+  align-items: center;
+  gap: 6px;
